# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public async Task<bool> PurchaseTicketsAsync(int eventId, int userId, int quantity)
{
    var semaphore = new SemaphoreSlim(1, 1);
    
    await semaphore.WaitAsync();
    
    try
    {
        using var context = new EventBookingContext();
        
        var eventInfo = await context.Events
            .Where(e => e.Id == eventId)
            .Select(e => new { e.AvailableSeats, e.MaxSeats })
            .FirstOrDefaultAsync();
            
        if (eventInfo == null)
            return false;
            
        if (eventInfo.AvailableSeats < quantity)
            return false;
            
        var purchase = new Purchase
        {
            EventId = eventId,
            UserId = userId,
            Quantity = quantity,
            PurchaseDate = DateTime.UtcNow
        };
        
        context.Purchases.Add(purchase);
        
        var updatedSeats = await context.Events
            .Where(e => e.Id == eventId && e.AvailableSeats >= quantity)
            .ExecuteUpdateAsync(setters => setters
                .SetProperty(e => e.AvailableSeats, e => e.AvailableSeats - quantity));
                
        if (updatedSeats == 0)
            return false;
            
        await context.SaveChangesAsync();
        return true;
    }
    catch
    {
        return false;
    }
    finally
    {
        semaphore.Release();
    }
}